151→    public Declarables nextcloudWebhookShardDeclarables() {
152→        DirectExchange exchange = new DirectExchange(NEXTCLOUD_WEBHOOK_DIRECT_EXCHANGE);
153→        List<Declarable> items = new ArrayList<>();
154→        for (int i = 0; i < NEXTCLOUD_WEBHOOK_SHARD_COUNT; i++) {
155→            Queue queue = QueueBuilder.durable(NEXTCLOUD_WEBHOOK_SHARD_QUEUE_PREFIX + i).build();
156→            String routingKey = NEXTCLOUD_WEBHOOK_SHARD_ROUTING_KEY_PREFIX + i;
157→            items.add(queue);
158→            items.add(BindingBuilder.bind(queue).to(exchange).with(routingKey));
159→        }
160→        return new Declarables(items);
161→    }
